import{_ as a,c as i,a as n,o as e}from"./app-CEcM0piI.js";const l={};function d(p,s){return e(),i("div",null,s[0]||(s[0]=[n(`<h2 id="object的静态函数" tabindex="-1"><a class="header-anchor" href="#object的静态函数"><span>Object的静态函数</span></a></h2><p>Object中有许多静态函数可以使用</p><h4 id="keys" tabindex="-1"><a class="header-anchor" href="#keys"><span>keys</span></a></h4><p>获取对象中所有的键</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const 0 = { uname: &#39;pink&#39;, age: 18 }</span></span>
<span class="line"><span>//1.获得所有的属性名</span></span>
<span class="line"><span>console.log(Object.keys(o))//返回数组[&#39;uname&#39;,&#39;age&#39;]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="values" tabindex="-1"><a class="header-anchor" href="#values"><span>values</span></a></h4><p>获取对象中所有的属性值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const 0 = { uname: &#39;pink&#39;, age: 18 }</span></span>
<span class="line"><span>//1.获得所有的属性名</span></span>
<span class="line"><span>console.log(Object.values(o))//返回数组[&#39;pink&#39;,&#39;18&#39;]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="assign" tabindex="-1"><a class="header-anchor" href="#assign"><span>assign</span></a></h4><p>静态方法常用于对象拷贝 经常使用的场景给对象添加属性</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//给○新增属性</span></span>
<span class="line"><span>const o = { name:&#39;佩奇&#39;,age:6 }</span></span>
<span class="line"><span>Object.assign(o, { gender: &#39;女&#39; })</span></span>
<span class="line"><span>console.log(o) //{name:&#39;佩奇&#39;, age: 6,gender:&#39;女&#39;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="数组" tabindex="-1"><a class="header-anchor" href="#数组"><span>数组</span></a></h1><h2 id="常见方法" tabindex="-1"><a class="header-anchor" href="#常见方法"><span>常见方法</span></a></h2><table><thead><tr><th>方法</th><th>作用</th><th>说明</th></tr></thead><tbody><tr><td>forEach</td><td>遍历数组</td><td>不返回数组，经常用于查找遍历数组元素</td></tr><tr><td>filter</td><td>过滤数组</td><td>返回新数组，返回的是筛选满足条件的数组元素</td></tr><tr><td>map</td><td>迭代数组</td><td>返回新数组，返回的是处理之后的数组元素，想要使用返回的新数组</td></tr><tr><td>reduce</td><td>累计器</td><td>返回累计处理的结果，经常用于求和等</td></tr></tbody></table><h4 id="reduce" tabindex="-1"><a class="header-anchor" href="#reduce"><span>reduce</span></a></h4><p>reduce返回累计处理的结果，经常用于求和等 如果有起始值，则把初始值累加到里面</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>arr.reduce(function(上一次值,当前值){},初始值)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>示例:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>constarr[1,5,8]</span></span>
<span class="line"><span>const total = arr.reduce(function （prev, current) {</span></span>
<span class="line"><span>	return prev + current</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span>console.Log(total)    //14</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>执行过程</strong></p><ol><li>如果没有起始值，则上一次值以数组的第一个数组元素的值</li><li>每一次循环，把返回值给做为下一次循环的上一次值</li><li>如果有起始值，则起始值做为上一次值</li></ol><h3 id="其他常见方法" tabindex="-1"><a class="header-anchor" href="#其他常见方法"><span>其他常见方法</span></a></h3><ol start="5"><li>实例方法join数组元素拼接为字符串，返回字符串(重点)</li><li>实例方法去find查找元素，返回符合测试条件的第一个数组元素值，如果没有符合条件的则返回undefined(重点)</li><li>实例方法every检测数组所有元素是否都符合指定条件，如果所有元素都通过检测返回true，否则返回false(重点)</li><li>实例方法some检测数组中的元素是否满足指定条件如果数组中有元素满足条件返回true，否则返回false</li><li>实例方法concat合并两个数组，返回生成新数组</li><li>实例方法去sort对原数组单元值排序</li><li>实例方法去splice删除或替换原数组单元</li><li>实例方法reverse反转数组</li><li>实例方法findIndex查找元素的索引值</li></ol><h1 id="字符串" tabindex="-1"><a class="header-anchor" href="#字符串"><span>字符串</span></a></h1><h3 id="常见方法-1" tabindex="-1"><a class="header-anchor" href="#常见方法-1"><span>常见方法</span></a></h3><ol><li>实例属性 length用来获取字符串的度长(重点)</li><li>实例方法split（&#39;分隔符&#39;）用来将字符串拆分成数组(重点)</li><li>实例方法去substring（需要截取的第一个字符的索引l[，结束的索引号]）用于字符串截取(重点)</li><li>实例方法startsWith（检测字符串[，检测位置索引号]）检测是否以某字符开头（重点）</li><li>实例方法includes（搜索的字符串[，检测位置索引号]）判断一个字符串是否包含在另一个字符串中，根据情况返回true或false(重点)</li><li>实例方法去toUpperCase用于将字母转换成大写</li><li>实例方法去toLowerCase用于将就转换成小写</li><li>实例方法indexof检测是否包含某字符</li><li>实例方法去endsWith检测是否以某字符结尾</li><li>实例方法replace用于替换字符串，支持正则匹配</li><li>实例方法match用于查找字符串，支持正则匹配</li></ol><h1 id="对象" tabindex="-1"><a class="header-anchor" href="#对象"><span>对象</span></a></h1><h2 id="创建对象的三种方式" tabindex="-1"><a class="header-anchor" href="#创建对象的三种方式"><span>创建对象的三种方式</span></a></h2><h3 id="利用对象字面量创建" tabindex="-1"><a class="header-anchor" href="#利用对象字面量创建"><span>利用对象字面量创建</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const A={</span></span>
<span class="line"><span>	name:&#39;pink&#39;,</span></span>
<span class="line"><span>	age:12</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="利用new-object创建" tabindex="-1"><a class="header-anchor" href="#利用new-object创建"><span>利用new Object创建</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const A=new Object({name:&#39;pink&#39;,age:12})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="利用构造函数创建" tabindex="-1"><a class="header-anchor" href="#利用构造函数创建"><span>利用构造函数创建</span></a></h3><p>构造函数在技术上是常规函数， 不过有两个约定： 它们的命名以大写字母开头。 它们只能由&quot;new”操作符来执行</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function Pig(name,age,gender){</span></span>
<span class="line"><span>	this.name = name</span></span>
<span class="line"><span>	this.age = age</span></span>
<span class="line"><span>	this.gener = gender</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>//创建佩奇对象</span></span>
<span class="line"><span>const Peppa =new Pig(&#39;佩奇&#39;,6,&#39;女&#39;)</span></span>
<span class="line"><span>//创建乔治对象</span></span>
<span class="line"><span>const George =new Pig(&#39;乔治&#39;,3,&#39;男&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>构造函数没有返回值</p><p>构造函数在创建对象的时候每个对象都有它对应的构造函数,也就是说静态方法都有一份,这样就造成了内存的浪费 这个问题可以使用原型来解决</p><h3 id="使用new关键字时做的事情" tabindex="-1"><a class="header-anchor" href="#使用new关键字时做的事情"><span>使用new关键字时做的事情</span></a></h3><p>当使用new关键字时会先创建一个空对象,然后在这个空对象中使用构造函数,所以构造函数的this指针才会指向新的对象</p><h4 id="静态成员" tabindex="-1"><a class="header-anchor" href="#静态成员"><span>静态成员</span></a></h4><p>构造函数的属性和方法被称为静态成员（静态属性和静态方法）</p><ol><li>静态成员只能构造函数来访问</li><li>静态方法中的this指向构造函数</li></ol><h2 id="原型" tabindex="-1"><a class="header-anchor" href="#原型"><span>原型</span></a></h2><h3 id="原型对象" tabindex="-1"><a class="header-anchor" href="#原型对象"><span>原型对象</span></a></h3><ul><li>构造函数通过原型分配的函数是所有对象所共享的。</li><li>JavaScript规定，每一个构造函数都有一个prototype 属性，指向另一个对象，所以我们也称为原型对象</li><li>这个对象可以挂载函数，对象实例化不会多次创建原型上函数，节约内存</li><li>我们可以把那些不变的方法，直接定义在prototype对象上，这样所有对象的实例就可以共享这些方法。</li><li>构造函数和原型对象中的this都指向实例化的对象</li></ul><p>将共有的函数写在原型里面,将私有的属性写在构造函数里面</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function Star（uname,age）{</span></span>
<span class="line"><span>	this.uname=uname</span></span>
<span class="line"><span>	this.age=age</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>Star.prototype.sing=function(){</span></span>
<span class="line"><span>	console.log(&quot;唱歌&quot;)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>构造函数和原型对象中的this都指向调用自己的实例化的对象</strong></p><h3 id="constructor" tabindex="-1"><a class="header-anchor" href="#constructor"><span>constructor</span></a></h3><p>每个原型对象里面都有个constructor属性（constructor构造函数） 该属性指向该原型对象的构造函数</p><p>给原型批量添加函数 在对象里面函数的赋值是使用冒号的, 但如果直接这样做就是创造了一个新的类型取代了star中的prototype属性</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Star.prototype ={</span></span>
<span class="line"><span>	sing: function (){</span></span>
<span class="line"><span>		console.log(&#39;唱歌&quot;）</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	dance: function(){</span></span>
<span class="line"><span>		console.log（‘跳舞）</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这时就需要让constructor重新指向构造函数,这样prototype属性就不会改变了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Star.prototype ={</span></span>
<span class="line"><span>	//从新指回创造这个原型对象的构造函数</span></span>
<span class="line"><span>	constructor: Star,</span></span>
<span class="line"><span>	sing: function (){</span></span>
<span class="line"><span>		console.log(&#39;唱歌&quot;）</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	dance: function(){</span></span>
<span class="line"><span>		console.log（‘跳舞）</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="对象原型" tabindex="-1"><a class="header-anchor" href="#对象原型"><span>对象原型</span></a></h3><p>对象都会有一个属性__proto__指向构造函数的prototype 原型对象，之所以我们对象可以使用构造函数prototype 原型对象的属性和方法，就是因为对象有__proto__原型的存在。 ![[Pasted image 20241103151926.png]] 对象原型指向原型对象</p><ul><li>_proto_是Js非标准属性</li><li>[[prototype]]和_proto__意义相同</li><li>用来表明当前实例对象指向哪个原型对象prototype</li><li>_proto_对象原型里面也有一个constructor属性，指向创建该实例对象的构造函数</li></ul><h2 id="原型继承" tabindex="-1"><a class="header-anchor" href="#原型继承"><span>原型继承</span></a></h2><p>继承是面向对象编程的另一个特征，通过继承进一步提升代码封装的程度，JavaScript中大多是借助原型对象实现继承的特性。</p><p>原型继承后也需要使用conrstructor指回对象</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Woman通过原型来继承Person</span></span>
<span class="line"><span>Woman.prototype = Person</span></span>
<span class="line"><span>//指回原来的构造函数</span></span>
<span class="line"><span>Woman.prototype.constructor =Woman</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但如果要给子类添加公共的成员函数就不能在原型对象;上挂载了,因为这样的继承是浅拷贝,其他的子类以及父类的原型对象也都是这个地址</p><p>可以使用new关键字创建一个新的对象用于继承</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Woman.prototype =new Person()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="原型链" tabindex="-1"><a class="header-anchor" href="#原型链"><span>原型链</span></a></h2><p>基于原型对象的继承使得不同构造函数的原型对象关联在一起，并且这种关联的关系是一种链状的结构，我们将原型对象的链状结构关系称为原型链 ![[Pasted image 20241103160423.png]]</p><p><strong>查找规则</strong></p><ol><li>当访问一个对象的属性（包括方法）时，首先查找这个对象自身有没有该属性。</li><li>如果没有就查找它的原型（也就是_proto_指向的prototype原型对象)</li><li>如果还没有就查找原型对象的原型（Object的原型对象）</li><li>依此类推一直找到Object为止（null)</li><li>_proto_对象原型的意义就在于为对象成员查找机制提供一个方向，或者说一条路线</li><li>可以使用instanceof 运算符用于检测构造函数的prototype属性是否出现在某个实例对象的原型链上</li></ol><h1 id="深拷贝和浅拷贝" tabindex="-1"><a class="header-anchor" href="#深拷贝和浅拷贝"><span>深拷贝和浅拷贝</span></a></h1><p>浅拷贝和深拷贝只针对引用类型</p><ol><li>拷贝对象：Object.assgin(）/展开运算符{..obj}拷贝对象</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const obj={</span></span>
<span class="line"><span>	name:&#39;pink&#39;,</span></span>
<span class="line"><span>	age:20</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>const o={}</span></span>
<span class="line"><span>Object.assgin(o,obj)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>拷贝数组：Array.prototype.concat或者[...arr]</li></ol><h2 id="深拷贝" tabindex="-1"><a class="header-anchor" href="#深拷贝"><span>深拷贝</span></a></h2><h3 id="通过递归实现深拷贝" tabindex="-1"><a class="header-anchor" href="#通过递归实现深拷贝"><span>通过递归实现深拷贝</span></a></h3><h3 id="使用js库lodash里面的clonedeep函数" tabindex="-1"><a class="header-anchor" href="#使用js库lodash里面的clonedeep函数"><span>使用js库lodash里面的cloneDeep函数</span></a></h3><h3 id="把对象转换为json字符串-拷贝后再解析为对象" tabindex="-1"><a class="header-anchor" href="#把对象转换为json字符串-拷贝后再解析为对象"><span>把对象转换为json字符串,拷贝后再解析为对象</span></a></h3><h1 id="异常处理" tabindex="-1"><a class="header-anchor" href="#异常处理"><span>异常处理</span></a></h1><p>除了try...catch...finally,js还有debuger关键字用来异常处理 直接添加debuger关键字程序在允许时会在debugger位置停止,即打断点</p><h1 id="this" tabindex="-1"><a class="header-anchor" href="#this"><span>this</span></a></h1><p>对象中并没有this,函数中才有this</p><p>箭头函数中的this与普通函数完全不同，也不受调用方式的影响，事实上箭头函数中并不存在this！</p><ol><li>箭头函数会默认帮我们绑定外层 this 的值，所以在箭头函数中 this 的值和外层的 this 是一样的</li><li>箭头函数中的this引用的就是最近作用域中的this</li><li>向外层作用域中，一层一层查找this，直到有this的定义</li></ol><h2 id="改变this的指向" tabindex="-1"><a class="header-anchor" href="#改变this的指向"><span>改变this的指向</span></a></h2><p>JavaScript中还允许指定函数中this的指向，有3个方法可以动态指定普通函数中this的指向</p><ul><li>call()</li><li>apply()</li><li>bind()</li></ul><h3 id="call" tabindex="-1"><a class="header-anchor" href="#call"><span>call</span></a></h3><p>使用call方法调用函数，同时指定被调用函数中this的值</p><ul><li>thisArg：在fun函数运行时指定的this值</li><li>arg1，arg2：传递的其他参数</li><li>返回值就是函数的返回值，因为它就是调用函数</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>fun.call(thisArg,arg1,arg2,...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>使用: 将fn中的this重定向为obj对象</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const obj ={</span></span>
<span class="line"><span>	uname:&#39;pink&#39;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>function fn(x, y) {</span></span>
<span class="line"><span>	console.log(this) // window</span></span>
<span class="line"><span>	console.log(x + y)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>//1.调用函数</span></span>
<span class="line"><span>// 2。改变 this 指向</span></span>
<span class="line"><span>fn.call(obj,1, 2)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="apply" tabindex="-1"><a class="header-anchor" href="#apply"><span>apply</span></a></h3><p>使用apply方法调用函数，同时指定被调用函数中this的值</p><ul><li>thisArg：在fun函数运行时指定的this值</li><li>argsArray：传递的值，必须包含在数组里面</li><li>返回值就是函数的返回值，因为它就是调用函数 因此apply主要跟数组有关系，比如使用Math.max(）求数组的最大值</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>fun.apply(thisArg,[argsArray])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>使用: 将fn中的this重定向为obj对象</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const obj ={</span></span>
<span class="line"><span>	age:18</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>function fn(x,y) {</span></span>
<span class="line"><span>	console.log(this) // {age: 18}</span></span>
<span class="line"><span>	console.log(x + y)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>// 1.调用函数</span></span>
<span class="line"><span>// 2。改变this指向</span></span>
<span class="line"><span>fn.apply(obj,[1,2])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="bind" tabindex="-1"><a class="header-anchor" href="#bind"><span>bind</span></a></h3><p>bind()方法不会调用函数。但是能改变函数内部this指向</p><ul><li>thisArg：在fun 函数运行时指定的 this 值</li><li>arg1，arg2：传递的其他参数sayHello()</li><li>返回由指定的this值和初始化参数改造的原函数拷贝（新函数） 因此当我们只是想改变this指向，并且不想调用这个函数的时候，可以使用bind，比如改变定时器内部的this指向.</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>fun.bind(thisArg,argl,arg2,...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const obj ={</span></span>
<span class="line"><span>	age:18</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>function fn() {</span></span>
<span class="line"><span>	console.log(this)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>const fun = fn.bind（obj)</span></span>
<span class="line"><span>fun()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="防抖" tabindex="-1"><a class="header-anchor" href="#防抖"><span>防抖</span></a></h1><p>单位时间内，频繁触发事件，只执行最后一次</p><h1 id="节流" tabindex="-1"><a class="header-anchor" href="#节流"><span>节流</span></a></h1><p>单位时间内，频繁触发事件，只执行一次</p>`,107)]))}const r=a(l,[["render",d]]),c=JSON.parse('{"path":"/front/js/5/","title":"5 面向对象","lang":"zh-CN","frontmatter":{"title":"5 面向对象","createTime":"2025/06/15 13:34:50","permalink":"/front/js/5/"},"readingTime":{"minutes":9.66,"words":2899},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/JavaScript/5 面向对象.md","headers":[]}');export{r as comp,c as data};
